import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Login = ({ onLogin }) => {
  const navigate = useNavigate();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Use the same baseURL as in App.js
  const API_URL = 'http://localhost:5002/api';

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await axios.post(`${API_URL}/auth/login`, 
        { username, password }, 
        { withCredentials: true }
      );
      if (res.data && res.data.success) {
        if (onLogin) onLogin(res.data.user);
        navigate('/dashboard');
      } else {
        setError(res.data.error || 'Login failed');
      }
    } catch (err) {
      console.error('Login error:', err);
      if (err.code === 'ERR_NETWORK') {
        setError('Cannot connect to server. Make sure backend is running on port 5002');
      } else {
        setError(err.response?.data?.error || 'Server error. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <div className="login-logo">AUTONOMOUS BILLING SYSTEM</div>
          <div className="login-subtitle">18000 18000</div>
        </div>
        <h2 className="login-title">Admin Login</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Username</label>
            <input 
              type="text" 
              value={username} 
              onChange={(e) => setUsername(e.target.value)} 
              placeholder="Enter username"
              required 
            />
          </div>
          <div className="form-group">
            <label>Password</label>
            <input 
              type="password" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              placeholder="Enter password"
              required 
            />
          </div>
          <div className="form-actions" style={{ marginTop: 16 }}>
            <button className="login-btn" type="submit" disabled={loading}>
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </div>
        </form>
        <div className="login-footer">
          <p style={{ marginTop: '16px', fontSize: '11px', color: '#999' }}>
            Demo: admin / admin123
          </p>
          <p>© 2026 Sairam Eng. M.Tech. All rights reserved.</p>
        </div>
      </div>
    </div>
  );
};

export default Login;
